package com.example.lessondesign.controller; import com.example.lessondesign.bean.*; import com.example.lessondesign.dao.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/classes") public class ClassController { @Autowired private ClassDao classDao; @Autowired private UserDao userDao; @Autowired private CourseDao courseDao; @GetMapping public ResponseEntity<List<Classes>> getAll(){ return ResponseEntity.ok(classDao.findAll()); } @GetMapping("/{id}") public ResponseEntity<Classes> getById(@PathVariable int id){ Classes c=classDao.findById(id); return c!=null?ResponseEntity.ok(c):ResponseEntity.notFound().build(); } @GetMapping("/teacher/{tid}") public ResponseEntity<List<Classes>> getByTeacher(@PathVariable String tid){ return ResponseEntity.ok(classDao.findByTeacherId(tid)); } @PostMapping("/create-with-students") public ResponseEntity<Map<String,Object>> createWithStudents(@RequestBody Classes c){ Map<String,Object> r=new HashMap<>(); try { c.setNumber(0);c.setProgress("Not started"); classDao.insert(c); r.put("success",true);r.put("classId",c.getId()); return ResponseEntity.ok(r); } catch(Exception e){ r.put("success",false);r.put("message",e.getMessage()); return ResponseEntity.status(500).body(r); } } }